/* global use, db */

/*
 * Oracle Database API for MongoDB: text search, vector search, and hybrid search
 * over the MFLIX movie dataset.
 *
 * Assumptions before running:
 *   - Database/user json_search exists.
 *   - mflix_movies contains the source movie documents.
 *   - mflix_movies_embeddings contains the same movie documents plus a
 *     384-dimensional plot_embedding array.
 *   - The ALL_MINILM_L12_V2 embedding model is loaded in Oracle Database.
 *
 * The script demonstrates:
 *   1. Creating a MongoDB API vector search index backed by Oracle.
 *   3. Generating a query embedding in Oracle through $sql.
 *   4. Running MongoDB API $vectorSearch.
 
 */

// -----------------------------------------------------------------------------
// 1. Demo collections
// -----------------------------------------------------------------------------

const database = "json_search";
use(database);

 

// -----------------------------------------------------------------------------
//  Generate the semantic-search query vector with Oracle SQL
// -----------------------------------------------------------------------------

// For each movie, mflix_movies_embeddings stores a 384-dimensional vector in
// plot_embedding. At query time, we generate an embedding for the user's natural
// language prompt and use it as the $vectorSearch queryVector.
//
// The $sql stage runs Oracle SQL from the MongoDB API. Here it calls
// VECTOR_EMBEDDING with the MiniLM model and serializes the vector as JSON.

const vectorRows = db.aggregate([
  {
    $sql: {
      statement: `
        WITH query_vector AS (
          SELECT vector_serialize(
                   vector_embedding(all_MiniLM_L12_v2 USING :1 AS DATA)
                   RETURNING CLOB
                 ) AS queryVector0
          FROM dual
        )
        SELECT queryVector0
        FROM query_vector
      `,
     binds : [ 
       {index:1, value:"epic fantasy journey with reluctant heroes"}
     ]
    },
  },
]).toArray();

// Convert the serialized SQL vector into a JavaScript number array accepted by
// $vectorSearch.
let queryVector0 = JSON.parse(vectorRows[0].QUERYVECTOR0).map(Number);
print("Query vector length: " + queryVector0.length);
//print("Query vector: " + queryVector0);
 
