let queryVector = JSON.parse(queryVector1).map(Number);
// -----------------------------------------------------------------------------
// 5. Semantic search with $vectorSearch
// -----------------------------------------------------------------------------
 
// Return the top 5 movies whose plot embeddings are closest to the prompt:
// "epic fantasy journey with reluctant heroes".
db.mflix_movies_embeddings.aggregate([
  {
    $vectorSearch: {
      index: "plot_vec_idx",
      path: "plot_embedding",
      queryVector: queryVector0,
      limit: 5,
      exact: false,
      hint: { "$preview": 1 },
    },
  },
  {
    $project: {
      _id: 0,
      title: 1,
      year: 1,
      genres: 1,
      fullplot: 1,
    },
  },
]);


// Semantic search with a metadata filter. $in means "is one of these values";
// here we keep movies tagged as Action, Adventure, or Sci-Fi.
db.mflix_movies_embeddings.aggregate([
  {
    $vectorSearch: {
      index: "plot_vec_idx",
      path: "plot_embedding",
      queryVector: queryVector,
      limit: 10,
      exact: false,
      hint: { "$preview": 1 },
    },
  },
  {
    $match: {
      genres: { $in: ["Action", "Adventure", "Sci-Fi"]}
    }
  },
  {
    $project: {
      _id: 0,
      title: 1,
      year: 1,
      genres: 1,
      fullplot: 1
    },
  },
]);

// Semantic search with post-search sorting. Use -1 for descending year order,
// or 1 for ascending year order.
db.mflix_movies_embeddings.aggregate([
  {
    $vectorSearch: {
      index: "plot_vec_idx",
      path: "plot_embedding",
      queryVector: queryVector,
      limit: 5,
      exact: false,
      hint: { "$preview": 1 },
    },
  },
  { $sort: { year: -1 } },
  {
    $project: {
      _id: 0,
      title: 1,
      year: 1,
      genres: 1,
      fullplot: 1,
    },
  },
]);
 
